import React, { useState } from 'react';
import './ContactForm.css';

export const ContactForm = () => {
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    subject: "",
    message: "",
  });

  const [errors, setErrors] = useState({});
  const [successMsg, setSuccessMsg] = useState("");
  const [loading, setLoading] = useState(false);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: value });
    if (errors[name]) setErrors({ ...errors, [name]: "" });
  };

  const validate = () => {
    const newErrors = {};
    if (!form.name.trim()) newErrors.name = "El nombre es obligatorio";
    if (!form.email.trim()) {
      newErrors.email = "El correo es obligatorio";
    } else if (!emailRegex.test(form.email)) {
      newErrors.email = "Correo inválido";
    }
    if (!form.subject) newErrors.subject = "Selecciona un asunto";
    if (!form.message.trim()) newErrors.message = "El mensaje es obligatorio";
    else if (form.message.trim().length < 10) newErrors.message = "Mínimo 10 caracteres";
    return newErrors;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const validationErrors = validate();
    setErrors(validationErrors);

    if (Object.keys(validationErrors).length === 0) {
      setLoading(true);
      setTimeout(() => {
        setLoading(false);
        setSuccessMsg("¡Mensaje enviado! Nos pondremos en contacto contigo pronto.");
        setForm({ name: "", email: "", phone: "", subject: "", message: "" });
        setErrors({});
        setTimeout(() => setSuccessMsg(""), 6000);
      }, 1200);
    }
  };

  return (
    <section className="cf-section" id="contacto">

      {/* Header */}
      <div className="cf-header">
        <h2 className="cf-titulo">Contáctanos</h2>
        <p className="cf-sub">¿Tienes dudas sobre un producto? Escríbenos y te respondemos a la brevedad.</p>
      </div>

      <div className="cf-wrapper">

        {/* Info lateral */}
        <div className="cf-info">
          <div className="cf-info-item">
            <div className="cf-info-icon">📍</div>
            <div>
              <p className="cf-info-label">Dirección</p>
              <p className="cf-info-valor">Av. La Marina 2100, San Miguel, Lima</p>
            </div>
          </div>
          <div className="cf-info-item">
            <div className="cf-info-icon">📞</div>
            <div>
              <p className="cf-info-label">Teléfono</p>
              <p className="cf-info-valor">+51 999 888 777</p>
            </div>
          </div>
          <div className="cf-info-item">
            <div className="cf-info-icon">✉️</div>
            <div>
              <p className="cf-info-label">Correo</p>
              <p className="cf-info-valor">soporte@techstore.pe</p>
            </div>
          </div>
          <div className="cf-info-item">
            <div className="cf-info-icon">🕐</div>
            <div>
              <p className="cf-info-label">Horario</p>
              <p className="cf-info-valor">Lun – Sáb: 9am – 8pm</p>
            </div>
          </div>

          <div className="cf-garantias">
            <div className="cf-garantia-item">
              <span className="cf-garantia-dot" />
              Garantía oficial 12 meses
            </div>
            <div className="cf-garantia-item">
              <span className="cf-garantia-dot" />
              Soporte técnico especializado
            </div>
            <div className="cf-garantia-item">
              <span className="cf-garantia-dot" />
              Respuesta en menos de 24h
            </div>
          </div>
        </div>

        {/* Formulario */}
        <div className="cf-form-card">
          {successMsg && (
            <div className="cf-success">
              <span className="cf-success-icon">✓</span>
              {successMsg}
            </div>
          )}

          <form className="cf-form" onSubmit={handleSubmit} noValidate>

            {/* Nombre + Teléfono */}
            <div className="cf-row">
              <div className="cf-group">
                <label className="cf-label">Nombre completo <span className="cf-required">*</span></label>
                <input
                  type="text"
                  name="name"
                  className={`cf-input ${errors.name ? "error" : ""}`}
                  value={form.name}
                  onChange={handleChange}
                  placeholder="Tu nombre"
                />
                {errors.name && <span className="cf-error">{errors.name}</span>}
              </div>
              <div className="cf-group">
                <label className="cf-label">Teléfono <span className="cf-opcional">(opcional)</span></label>
                <input
                  type="tel"
                  name="phone"
                  className="cf-input"
                  value={form.phone}
                  onChange={handleChange}
                  placeholder="+51 999 000 000"
                />
              </div>
            </div>

            {/* Email + Asunto */}
            <div className="cf-row">
              <div className="cf-group">
                <label className="cf-label">Correo electrónico <span className="cf-required">*</span></label>
                <input
                  type="email"
                  name="email"
                  className={`cf-input ${errors.email ? "error" : ""}`}
                  value={form.email}
                  onChange={handleChange}
                  placeholder="ejemplo@correo.com"
                />
                {errors.email && <span className="cf-error">{errors.email}</span>}
              </div>
              <div className="cf-group">
                <label className="cf-label">Asunto <span className="cf-required">*</span></label>
                <select
                  name="subject"
                  className={`cf-input cf-select ${errors.subject ? "error" : ""}`}
                  value={form.subject}
                  onChange={handleChange}
                >
                  <option value="">Seleccionar...</option>
                  <option value="consulta">Consulta de producto</option>
                  <option value="garantia">Garantía / Soporte</option>
                  <option value="pedido">Estado de pedido</option>
                  <option value="devolucion">Devolución</option>
                  <option value="otro">Otro</option>
                </select>
                {errors.subject && <span className="cf-error">{errors.subject}</span>}
              </div>
            </div>

            {/* Mensaje */}
            <div className="cf-group">
              <label className="cf-label">Mensaje <span className="cf-required">*</span></label>
              <textarea
                name="message"
                className={`cf-input cf-textarea ${errors.message ? "error" : ""}`}
                value={form.message}
                onChange={handleChange}
                placeholder="¿En qué te podemos ayudar?"
                rows="5"
              />
              <div className="cf-char-row">
                {errors.message && <span className="cf-error">{errors.message}</span>}
                <span className="cf-char-count">{form.message.length} caracteres</span>
              </div>
            </div>

            <button type="submit" className="cf-btn-submit" disabled={loading}>
              {loading ? (
                <span className="cf-loading">
                  <span className="cf-spinner" /> Enviando...
                </span>
              ) : (
                "Enviar Mensaje"
              )}
            </button>

          </form>
        </div>
      </div>
    </section>
  );
};
